#include <stdio.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buf[256];
    // consume the newline after T
    fgets(buf, sizeof(buf), stdin);
    for (int i = 0; i < T; ++i) {
        // read and ignore the description line
        if (!fgets(buf, sizeof(buf), stdin)) break;
        size_t len = strlen(buf);
        if (len && buf[len-1] == '\n') buf[len-1] = '\0';
        printf("Mean imputation and regression imputation are two techniques used for handling missing data.\n");
        printf("Mean imputation replaces missing values with the mean of the respective feature, while regression imputation uses a regression model to predict the missing values.\n");
    }
    return 0;
}

